(()=>{async function l(){const e=document.getElementById("cronTbody");if(e){e.innerHTML="<tr class='empty-row'><td colspan='6'>\u52A0\u8F7D\u4E2D...</td></tr>";try{const n=await Api.get("/cron");if(!n.success){e.innerHTML="<tr><td colspan='6'>"+n.message+"</td></tr>";return}const d=n.data.jobs||[];if(d.length===0){e.innerHTML="<tr class='empty-row'><td colspan='6'>\u6682\u65E0\u5B9A\u65F6\u4EFB\u52A1<br><small>\u70B9\u51FB\u300C\u6DFB\u52A0\u4EFB\u52A1\u300D\u521B\u5EFA</small></td></tr>";return}e.innerHTML=d.map(t=>{var a=t.interval<6e4?(t.interval/1e3).toFixed(0)+"\u79D2":t.interval<36e5?(t.interval/6e4).toFixed(0)+"\u5206\u949F":(t.interval/36e5).toFixed(1)+"\u5C0F\u65F6",s=t.lastRun?new Date(t.lastRun).toLocaleString("zh-CN"):"\u4ECE\u672A\u6267\u884C",r=t.enabled?"<span style='color:var(--success);'>\u542F\u7528\u4E2D</span>":"<span style='color:var(--text-secondary);'>\u5DF2\u505C\u7528</span>",o="<button class='btn btn-sm' data-jobid='"+t.id+"' data-action='toggle'>"+(t.enabled?"\u505C\u7528":"\u542F\u7528")+"</button>";return"<tr><td><strong>"+t.name+"</strong></td><td>"+t.type+"</td><td>"+a+"</td><td><small>"+s+"</small></td><td>"+r+"</td><td>"+o+"</td></tr>"}).join(""),document.querySelectorAll("#cronTbody [data-action='toggle']").forEach(t=>{t.addEventListener("click",async function(){await Api.post("/cron/"+this.dataset.jobid+"/toggle"),l()})})}catch(n){e.innerHTML="<tr><td colspan='6'>\u52A0\u8F7D\u5931\u8D25: "+n.message+"</td></tr>"}}}(function e(){if(document.readyState==="loading"){document.addEventListener("DOMContentLoaded",e);return}document.getElementById("btnCronAdd")?.addEventListener("click",()=>{Utils.openModal("\u6DFB\u52A0\u5B9A\u65F6\u4EFB\u52A1",`
      <div class="form-group">
        <label>\u4EFB\u52A1\u540D\u79F0</label>
        <input type="text" id="cronAddName" class="form-input" placeholder="\u4F8B\u5982\uFF1ADDNS \u81EA\u52A8\u5237\u65B0">
      </div>
      <div class="form-group">
        <label>\u6267\u884C\u95F4\u9694\uFF08\u79D2\uFF09</label>
        <input type="number" id="cronAddInterval" class="form-input" value="3600" min="60" max="86400">
      </div>
      <div class="form-group">
        <label>\u6267\u884C\u547D\u4EE4/API</label>
        <select id="cronAddType" class="form-input">
          <option value="ddns_refresh">\u5237\u65B0 DDNS</option>
          <option value="custom">\u81EA\u5B9A\u4E49 API</option>
        </select>
      </div>
      <div class="form-group" id="cronAddCustomGroup" style="display:none">
        <label>\u76EE\u6807 API \u8DEF\u5F84</label>
        <input type="text" id="cronAddApiPath" class="form-input" placeholder="\u4F8B\u5982\uFF1A/api/ddns/refresh">
      </div>
    `,`
      <button class="btn btn-secondary" onclick="Utils.closeModal()">\u53D6\u6D88</button>
      <button class="btn btn-success" id="cronAddConfirm">\u2705 \u6DFB\u52A0\u4EFB\u52A1</button>
    `),document.getElementById("cronAddType").addEventListener("change",function(){document.getElementById("cronAddCustomGroup").style.display=this.value==="custom"?"block":"none"}),document.getElementById("cronAddConfirm").addEventListener("click",async()=>{const t=document.getElementById("cronAddName").value.trim()||"\u5B9A\u65F6\u4EFB\u52A1",a=parseInt(document.getElementById("cronAddInterval").value)||3600,s=document.getElementById("cronAddType").value,r=document.getElementById("cronAddApiPath").value.trim();Utils.closeModal(),Utils.notify("\u6B63\u5728\u6DFB\u52A0...","info");const o=await Api.post("/cron",{name:t,interval:a*1e3,type:s,apiPath:r});o.success?(Utils.notify(o.message||"\u5B9A\u65F6\u4EFB\u52A1\u5DF2\u6DFB\u52A0","success"),l()):Utils.notify(o.message||"\u6DFB\u52A0\u5931\u8D25","error")})})})();window.loadCron=l;})();
